// Calculate optimal retry time based on failure code and day of week
const attempt = $input.first().json;
const failureCode = attempt.failure_code || '';
const now = new Date();
const hour = now.getHours();
const dayOfWeek = now.getDay(); // 0=Sun, 6=Sat

// Optimal retry windows: weekdays 10am-12pm or 6pm-8pm
let delayHours = 4; // default

if (failureCode === 'insufficient_funds') {
  // Retry near payday: 1st and 15th of month
  const today = now.getDate();
  const nextPayday = today < 15 ? 15 : new Date(now.getFullYear(), now.getMonth() + 1, 1).getDate();
  const daysUntilPayday = nextPayday - today;
  delayHours = daysUntilPayday * 24 + 10; // 10am on payday
} else if (failureCode === 'card_declined') {
  delayHours = 24; // retry next day
} else if (failureCode === 'expired_card') {
  delayHours = 2; // quick email to update card
} else {
  // Avoid weekends for retries
  if (dayOfWeek === 5) delayHours = 72; // Friday → Monday
  else if (dayOfWeek === 6) delayHours = 48; // Saturday → Monday
  else if (hour < 9) delayHours = 9 - hour; // wait until 9am
  else if (hour > 20) delayHours = 24 - hour + 9; // wait until next day 9am
}

return [{ json: { ...attempt, optimal_delay_hours: delayHours } }];
